import{_ as t,o as e,c as _,a as p}from"./app.7f9bd173.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"article/2022.11.4.md"}'),a={name:"article/2022.11.4.md"},o=p("<h1>秋末 冬初 有感</h1><p>作者: 孙飞</p><p>日期: 2022.11.4</p><hr><p>一转眼，秋天过去了，从满怀期待，到内心的平静。印证了那句话:未曾拥有的永远都是美好的。可但真正身处其境，你又真的很开心吗? <p>温度一下子降了下来，从窗口望向远方的村庄，我又想起来了家。那里可以接受我的小脾气，也可以给予满满的安全感。 凌晨6点钟，窗外是迷糊的，大抵是没戴眼镜的原因吧。回想起几个月的前，满怀激动的我写的承诺，我又做到了几条呢。本以为崭新的开始，就可以让我的人生充实起来，可到最后还不是毁于自己。甘心吗?悔恨吗? 内心的谴责一遍又一遍的鞭策着自己，你又怎么甘心认输呢。</p><p>你总是一遍又一遍在深夜的床头，羡慕着别人生活多美好，感情，友情。可是你又是否为此而鉴定的努力过呢?不过一边羡慕别人给自己制造焦虑，一边又假装努力安抚内心罢了。可是这东西又怎能欺骗而得到呢。</p><p>醒醒吧，没有意义的人际关系及时断掉，有什么可维护的，付出了精力，付出了真心，最后别人再从你背后给你一刀。到那时候，悔恨也来不及。所以，做一个心狠的人，更千万别放低自己。</p><p>利用时间多去提升自己，比和女人聊天强上一万倍，况且你的情绪你还不了解吗，别人随口一句话，你的情绪就特别混乱，然后贬低自己。这样是不对的，好女人会有的，互相交心的人也是会有的，所以啊现在好好提升自己，强大自己了，才是谁也拿不走的。</p><p>对方爱回不回，那是别人的权利；对方想回啥就回啥，那也是别人的权利；对方有一万个异性朋友，那也是别人的权利；所以，尊重即可，己所不欲勿施于人。不要以为自己是中心，别人会围着你转。相比之下好好学习，学好本事，别人才会尊重你。所以简而言之，拿出实力说话。</p><p>转眼就要冬天了，规划好的事情，就去按部就班的去努力吧，遇到困难不要害怕，谁不是第一次呢，遇到困难，解决困难何尝不是一种成就感。不要急功求利，高楼是一步一步建成的，如果底层就踏踏实实的干，高层也不会发生坍塌的事故。</p></p>",5),r=[o];function c(s,n,i,d,l,h){return e(),_("div",null,r)}const T=t(a,[["render",c]]);export{f as __pageData,T as default};
